import { getVal, simpleClone } from '../../../utils/zcutils';
import { effects } from '../../../effects/zceffects';

function getByGradient(_, applied) {
    let { context, defsPath = '', rendererMode = 'svg', dimension = [0, 300] } = _,
        { color } = applied;

    return (d, i) => {
        let _color = getVal(color, [d, i]),
            fillOpacity = 0,
            prop = getGradientProp(applied, dimension, _color, fillOpacity),
            gradientEle = effects.get(effects[`${rendererMode}_gradients`], `${rendererMode}GradientFill`, prop, { renderTo: context });

        return rendererMode === 'svg' ? `url(${defsPath}#${gradientEle})` : gradientEle;
    };
}

function getGradientProp(applied, dimension, color, opacity) {
    let type = applied.gradient;
    var options = applied;
    var prop = simpleClone({ ...options, chart: undefined, context: undefined }); // TODO: context
    // let stopColor = [],
    //     stopOpacity = [],
    //     stopOffset = [];

    // let { stops = [] } = prop;
    // stops.forEach((_, i) => {
    //     if (_.color) {
    //         stopColor[i] = _.color;
    //     }
    //     if (_.opacity) {
    //         stopOpacity[i] = _.opacity;
    //     }
    //     if (_.offset) {
    //         stopOffset[i] = _.offset;
    //     }
    // });

    prop.color = color != null ? color : prop.color;
    prop.opacity = opacity != null ? opacity : prop.opacity;
    prop.dimension = dimension != null ? dimension : prop.dimension;
    prop.type = type;

    return {
        ...prop
        // stopColor: stopColor.length ? stopColor : prop.stopColor,
        // stopOpacity: stopOpacity.length ? stopOpacity : prop.stopOpacity,
        // stopOffset: stopOffset.length ? stopOffset : prop.stopOffset
    };
}

export { getByGradient };
